func (as *AuthService) AuthenticateAndCreateToken(username, password string) (string, *User, error) {
	as.mu.RLock()
	defer as.mu.RUnlock()

	for _, user := range as.users {
		if user.Username == username {
			token := as.generateSecureToken(user)
			user.SessionToken = token
			return token, user, nil
		}
	}
	return "", nil, fmt.Errorf("authentication failed")
}

func (as *AuthService) generateSecureToken(user *User) string {
	data := fmt.Sprintf("%s:%s:%d", user.ID, user.Role, time.Now().Unix())
	h := hmac.New(sha256.New, as.serverSecret)
	h.Write([]byte(data))
	signature := h.Sum(nil)
	token := base64.StdEncoding.EncodeToString([]byte(data + ":" + base64.StdEncoding.EncodeToString(signature)))
	return token
}

func (as *AuthService) ValidateToken(token string) (*User, error) {
	decoded, err := base64.StdEncoding.DecodeString(token)
	if err != nil {
		return nil, fmt.Errorf("invalid token format")
	}

	parts := strings.Split(string(decoded), ":")
	if len(parts) != 4 {
		return nil, fmt.Errorf("invalid token structure")
	}

	userID := parts[0]
	role := Role(parts[1])
	signature := parts[3]

	data := fmt.Sprintf("%s:%s:%s", parts[0], parts[1], parts[2])
	h := hmac.New(sha256.New, as.serverSecret)
	h.Write([]byte(data))
	expectedSignature := base64.StdEncoding.EncodeToString(h.Sum(nil))

	if !hmac.Equal([]byte(signature), []byte(expectedSignature)) {
		return nil, fmt.Errorf("invalid token signature")
	}

	as.mu.RLock()
	user, exists := as.users[userID]
	as.mu.RUnlock()

	if !exists {
		return nil, fmt.Errorf("user not found")
	}

	if user.Role != role {
		return nil, fmt.Errorf("role mismatch - token tampering detected")
	}

	return user, nil
}

