func (gs *GameServer) Run() {
	for {
		select {
		case client := <-gs.register:
			gs.mu.Lock()
			gs.clients[client] = true
			gs.users[client.user.ID] = client.user
			gs.mu.Unlock()
			log.Printf("Client registered: %s (Role: %s)", client.user.Username, client.user.Role)

		case client := <-gs.unregister:
			gs.mu.Lock()
			if _, ok := gs.clients[client]; ok {
				delete(gs.clients, client)
				close(client.sendChan)
			}
			gs.mu.Unlock()

		case message := <-gs.broadcast:
			gs.mu.RLock()
			for client := range gs.clients {
				select {
				case client.sendChan <- gs.marshalMessage(message):
				default:
					close(client.sendChan)
					delete(gs.clients, client)
				}
			}
			gs.mu.RUnlock()
		}
	}
}

func (gs *GameServer) marshalMessage(msg Message) []byte {
	data, _ := json.Marshal(msg)
	return data
}

func (gs *GameServer) hasPermission(user *User, requiredRole Role) bool {
	if user == nil {
		return false
	}

	if !time.Now().After(user.BannedUntil) {
		return false
	}

	userLevel, userExists := roleHierarchy[user.Role]
	requiredLevel, reqExists := roleHierarchy[requiredRole]

	if !userExists || !reqExists {
		return false
	}

	return userLevel >= requiredLevel
}

func (gs *GameServer) findClientByUsername(username string) *Client {
	gs.mu.RLock()
	defer gs.mu.RUnlock()

	for client := range gs.clients {
		if client.user.Username == username {
			return client
		}
	}
	return nil
}

func (gs *GameServer) handleCommand(client *Client, content string) {
	parts := strings.Fields(content)
	if len(parts) == 0 {
		return
	}

	command := parts[0]

	switch command {
	case "/kick":
		if !gs.hasPermission(client.user, RoleMod) {
			client.sendChan <- gs.marshalMessage(Message{
				Type:      "error",
				Content:   "Insufficient permissions to kick users",
				Timestamp: time.Now(),
			})
			return
		}

		if len(parts) < 2 {
			client.sendChan <- gs.marshalMessage(Message{
				Type:      "error",
				Content:   "Usage: /kick <username>",
				Timestamp: time.Now(),
			})
			return
		}

		targetUsername := parts[1]
		targetClient := gs.findClientByUsername(targetUsername)

		if targetClient == nil {
			client.sendChan <- gs.marshalMessage(Message{
				Type:      "error",
				Content:   "User not found",
				Timestamp: time.Now(),
			})
			return
		}

		if roleHierarchy[targetClient.user.Role] >= roleHierarchy[client.user.Role] {
			client.sendChan <- gs.marshalMessage(Message{
				Type:      "error",
				Content:   "Cannot kick users with equal or higher privileges",
				Timestamp: time.Now(),
			})
			return
		}

		gs.broadcast <- Message{
			Type:      "system",
			Content:   fmt.Sprintf("%s has been kicked by %s", targetUsername, client.user.Username),
			Timestamp: time.Now(),
		}

		targetClient.conn.Close()
		gs.unregister <- targetClient

	case "/ban":
		if !gs.hasPermission(client.user, RoleAdmin) {
			client.sendChan <- gs.marshalMessage(Message{
				Type:      "error",
				Content:   "Insufficient permissions to ban users",
				Timestamp: time.Now(),
			})
			return
		}

		if len(parts) < 2 {
			client.sendChan <- gs.marshalMessage(Message{
				Type:      "error",
				Content:   "Usage: /ban <username> [duration_minutes]",
				Timestamp: time.Now(),
			})
			return
		}

		targetUsername := parts[1]
		duration := 60
		if len(parts) >= 3 {
			fmt.Sscanf(parts[2], "%d", &duration)
		}

		targetClient := gs.findClientByUsername(targetUsername)
		if targetClient == nil {
			client.sendChan <- gs.marshalMessage(Message{
				Type:      "error",
				Content:   "User not found",
				Timestamp: time.Now(),
			})
			return
		}

		if roleHierarchy[targetClient.user.Role] >= roleHierarchy[client.user.Role] {
			client.sendChan <- gs.marshalMessage(Message{
				Type:      "error",
				Content:   "Cannot ban users with equal or higher privileges",
				Timestamp: time.Now(),
			})
			return
		}

		targetClient.user.BannedUntil = time.Now().Add(time.Duration(duration) * time.Minute)

		gs.broadcast <- Message{
			Type:      "system",
			Content:   fmt.Sprintf("%s has been banned by %s for %d minutes", targetUsername, client.user.Username, duration),
			Timestamp: time.Now(),
		}

		targetClient.conn.Close()
		gs.unregister <- targetClient

	case "/giveitems":
		if !gs.hasPermission(client.user, RoleAdmin) {
			client.sendChan <- gs.marshalMessage(Message{
				Type:      "error",
				Content:   "Insufficient permissions to give items",
				Timestamp: time.Now(),
			})
			return
		}

		if len(parts) < 3 {
			client.sendChan <- gs.marshalMessage(Message{
				Type:      "error",
				Content:   "Usage: /giveitems <username> <item>",
				Timestamp: time.Now(),
			})
			return
		}

		targetUsername := parts[1]
		item := parts[2]

		targetClient := gs.findClientByUsername(targetUsername)
		if targetClient == nil {
			client.sendChan <- gs.marshalMessage(Message{
				Type:      "error",
				Content:   "User not found",
				Timestamp: time.Now(),
			})
			return
		}

		targetClient.sendChan <- gs.marshalMessage(Message{
			Type:      "item_grant",
			Content:   fmt.Sprintf("You received: %s", item),
			Timestamp: time.Now(),
			Data: map[string]string{
				"item": item,
			},
		})

		client.sendChan <- gs.marshalMessage(Message{
			Type:      "success",
			Content:   fmt.Sprintf("Gave %s to %s", item, targetUsername),
			Timestamp: time.Now(),
		})

	default:
		client.sendChan <- gs.marshalMessage(Message{
			Type:      "error",
			Content:   "Unknown command",
			Timestamp: time.Now(),
		})
	}
}

func (c *Client) readPump() {
	defer func() {
		c.server.unregister <- c
		c.conn.Close()
	}()

	c.conn.SetReadDeadline(time.Now().Add(60 * time.Second))
	c.conn.SetPongHandler(func(string) error {
		c.conn.SetReadDeadline(time.Now().Add(60 * time.Second))
		return nil
	})

	for {
		var msg Message
		err := c.conn.ReadJSON(&msg)
		if err != nil {
			break
		}

		if !c.server.hasPermission(c.user, RoleUser) {
			c.sendChan <- c.server.marshalMessage(Message{
				Type:      "error",
				Content:   "You are banned",
				Timestamp: time.Now(),
			})
			continue
		}

		if strings.HasPrefix(msg.Content, "/") {
			c.server.handleCommand(c, msg.Content)
		} else {
			msg.From = c.user.Username
			msg.Timestamp = time.Now()
			msg.Type = "chat"
			c.server.broadcast <- msg
		}
	}
}

func (c *Client) writePump() {
	ticker := time.NewTicker(54 * time.Second)
	defer func() {
		ticker.Stop()
		c.conn.Close()
	}()

	for {
		select {
		case message, ok := <-c.sendChan:
			c.conn.SetWriteDeadline(time.Now().Add(10 * time.Second))
			if !ok {
				c.conn.WriteMessage(websocket.CloseMessage, []byte{})
				return
			}

			w, err := c.conn.NextWriter(websocket.TextMessage)
			if err != nil {
				return
			}
			w.Write(message)

			n := len(c.sendChan)
			for i := 0; i < n; i++ {
				w.Write([]byte{'\n'})
				w.Write(<-c.sendChan)
			}

			if err := w.Close(); err != nil {
				return
			}

		case <-ticker.C:
			c.conn.SetWriteDeadline(time.Now().Add(10 * time.Second))
			if err := c.conn.WriteMessage(websocket.PingMessage, nil); err != nil {
				return
			}
		}
	}
}

var upgrader = websocket.Upgrader{
	ReadBufferSize:  1024,
	WriteBufferSize: 1024,
	CheckOrigin: func(r *http.Request) bool {
		return true
	},
}

func generateID() string {
	b := make([]byte, 16)
	rand.Read(b)
	return base64.URLEncoding.EncodeToString(b)
}

func generateSecret() []byte {
	secret := make([]byte, 32)
	rand.Read(secret)
	return secret
}

func main() {
	serverSecret := generateSecret()
	authService := NewAuthService(serverSecret)
	gameServer := NewGameServer(serverSecret)

	adminUser, _ := authService.CreateUser("admin", "password", RoleAdmin)
	modUser, _ := authService.CreateUser("moderator", "password", RoleMod)
	normalUser, _ := authService.CreateUser("user", "password", RoleUser)

	log.Printf("Created users: admin, moderator, user")
	log.Printf("Admin: %s", adminUser.Username)
	log.Printf("Mod: %s", modUser.Username)
	log.Printf("User: %s", normalUser.Username)

	go gameServer.Run()

	http.HandleFunc("/login", func(w http.ResponseWriter, r *http.Request) {
		var loginReq struct {
			Username string `json:"username"`
			Password string `json:"password"`
		}

		if err := json.NewDecoder(r.Body).Decode(&loginReq); err != nil {
			http.Error(w, "Invalid request", http.StatusBadRequest)
			return
		}

		token, user, err := authService.AuthenticateAndCreateToken(loginReq.Username, loginReq.Password)
		if err != nil {
			http.Error(w, "Authentication failed", http.StatusUnauthorized)
			return
		}

		response := map[string]interface{}{
			"token":    token,
			"username": user.Username,
			"role":     user.Role,
		}

		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(response)
	})

	http.HandleFunc("/ws", func(w http.ResponseWriter, r *http.Request) {
		authHeader := r.Header.Get("Authorization")
		if !strings.HasPrefix(authHeader, "Bearer ") {
			http.Error(w, "Missing or invalid authorization header", http.StatusUnauthorized)
			return
		}

		token := strings.TrimPrefix(authHeader, "Bearer ")

		user, err := authService.ValidateToken(token)
		if err != nil {
			log.Printf("Token validation failed: %v", err)
			http.Error(w, "Invalid token", http.StatusUnauthorized)
			return
		}

		if !time.Now().After(user.BannedUntil) {
			http.Error(w, "User is banned", http.StatusForbidden)
			return
		}

		conn, err := upgrader.Upgrade(w, r, nil)
		if err != nil {
			log.Println(err)
			return
		}

		client := &Client{
			conn:     conn,
			user:     user,
			server:   gameServer,
			sendChan: make(chan []byte, 256),
		}

		gameServer.register <- client

		go client.writePump()
		go client.readPump()
	})

	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "text/html")
		fmt.Fprintf(w, `
<!DOCTYPE html>
<html>
<head>
    <title>Game Server</title>
</head>
<body>
    <h1>Game Server</h1>
    <div id="login">
        <input type="text" id="username" placeholder="Username">
        <input type="password" id="password" placeholder="Password">
        <button onclick="login()">Login</button>
    </div>
    <div id="chat" style="display:none;">
        <div id="messages" style="height:400px;overflow-y:scroll;border:1px solid black;"></div>
        <input type="text" id="message" placeholder="Message">
        <button onclick="sendMessage()">Send</button>
    </div>
    <script>
        let ws;
        let token;
        
        function login() {
            const username = document.getElementById('username').value;
            const password = document.getElementById('password').value;
            
            fetch('/login', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({username, password})
            })
            .then(r => r.json())
            .then(data => {
                token = data.token;
                document.getElementById('login').style.display = 'none';
                document.getElementById('chat').style.display = 'block';
                connectWebSocket();
            });
        }
        
        function connectWebSocket() {
            ws = new WebSocket('ws://' + window.location.host + '/ws');
            ws.onopen = () => {
                ws.send(JSON.stringify({type: 'auth', token: token}));
            };
            ws.onmessage = (e) => {
                const msg = JSON.parse(e.data);
                const div = document.getElementById('messages');
                div.innerHTML += '<div>' + msg.from + ': ' + msg.content + '</div>';
                div.scrollTop = div.scrollHeight;
            };
        }
        
        function sendMessage() {
            const msg = document.getElementById('message').value;
            ws.send(JSON.stringify({type: 'chat', content: msg}));
            document.getElementById('message').value = '';
        }
        
        document.getElementById('message').addEventListener('keypress', (e) => {
            if (e.key === 'Enter') sendMessage();
        });
    </script>
</body>
</html>
`)
	})

	log.Println("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}